/**
 * scripts/gen-eri-version.mjs
 *
 * Reads the current @eri/components version from packages/eri-components/package.json
 * and writes it into shared/eriVersion.ts as a typed constant.
 *
 * Run automatically via the "prebuild" and "predev" npm scripts so the file is
 * always up to date before the client or server bundles are built.
 *
 * The generated file is committed to git so the dev server works without running
 * the script manually, but it must be regenerated whenever the package version changes.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, "..");

const pkg = JSON.parse(
  fs.readFileSync(path.join(root, "packages", "eri-components", "package.json"), "utf-8")
);

const version = `v${pkg.version}`;

const output = `// AUTO-GENERATED — do not edit manually.
// Re-generated by scripts/gen-eri-version.mjs whenever @eri/components version changes.
// Source of truth: packages/eri-components/package.json
export const ERI_COMPONENTS_VERSION = "${version}" as const;
`;

const outPath = path.join(root, "shared", "eriVersion.ts");
fs.writeFileSync(outPath, output, "utf-8");
console.log(`[gen-eri-version] wrote ${outPath} → ${version}`);
